-- ============================================
-- Legislacao full-site: geraldo-alckmin / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/65480
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = geraldo-alckmin-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 100 rows Camara legacy existentes, somente 98
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=65480, tipo Deputado(a), ordemAssinatura=1.
-- 2 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'geraldo-alckmin';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'geraldo-alckmin: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao geraldo-alckmin: esperadas 100 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('247199', '242941', '234878', '233212', '229257', '228484', '226867', '222023', '216799', '214842', '208809', '202180', '197562', '192536', '189647', '185081', '184331', '180298', '179671', '170698', '21230', '233320', '229657', '229039', '227650', '222881', '217009', '215748', '213151', '206535', '197958', '195659', '191267', '187656', '184360', '182248', '180251', '171522', '21373', '233258', '229544', '229035', '226966', '225476', '222839', '216874', '215087', '212319', '204443', '197785', '195577', '190055', '187563', '184345', '180314', '179914', '170714', '21364', '234499', '229253', '228480', '226677', '223982', '221106', '216342', '214537', '207273', '201963', '196927', '192523', '189573', '184824', '183976', '180281', '178962', '167224', '21221', '233455', '229775', '229249', '228476', '225664', '223823', '217409', '215935', '213160', '206563', '196281', '191437', '188115', '184809', '182846', '180266', '178286', '25761', '240938', '233191', '200252');
  IF target_present <> 98 THEN
    RAISE EXCEPTION 'Pre-condicao geraldo-alckmin: esperadas 98 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('247199', '242941', '234878', '233212', '229257', '228484', '226867', '222023', '216799', '214842', '208809', '202180', '197562', '192536', '189647', '185081', '184331', '180298', '179671', '170698', '21230', '233320', '229657', '229039', '227650', '222881', '217009', '215748', '213151', '206535', '197958', '195659', '191267', '187656', '184360', '182248', '180251', '171522', '21373', '233258', '229544', '229035', '226966', '225476', '222839', '216874', '215087', '212319', '204443', '197785', '195577', '190055', '187563', '184345', '180314', '179914', '170714', '21364', '234499', '229253', '228480', '226677', '223982', '221106', '216342', '214537', '207273', '201963', '196927', '192523', '189573', '184824', '183976', '180281', '178962', '167224', '21221', '233455', '229775', '229249', '228476', '225664', '223823', '217409', '215935', '213160', '206563', '196281', '191437', '188115', '184809', '182846', '180266', '178286', '25761', '240938', '233191', '200252')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'geraldo-alckmin-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao geraldo-alckmin: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao geraldo-alckmin: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

